import java.util.*;
import java.util.function.*;
public class MemoizeLambda {
    static <K,V> Function<K,V> memoize(Function<K,V> fn) {
        Map<K,V> cache = new HashMap<>();
        return k -> cache.computeIfAbsent(k, fn);
    }
    public static void main(String[] args) {
        int[] callCount = {0};
        Function<Integer,Integer> square = memoize(n -> { callCount[0]++; return n*n; });
        System.out.println(square.apply(5));
        System.out.println(square.apply(5));
        System.out.println(square.apply(3));
        System.out.println(callCount[0]);
    }
}
